# run_all.ps1 — Run all endpoint tests and print a final summary.
# Usage: .\test_scripts\run_all.ps1
# Requires the server to be running: uvicorn src.main:app --reload --port 8000

$ErrorActionPreference = "Continue"
$ScriptDir = $PSScriptRoot

$tests = @(
    "test_health.ps1",
    "test_stream_errors.ps1",
    "test_stream_json.ps1",
    "test_stream_multipart.ps1",
    "test_stream_prompt.ps1"
)

$totalPassed = 0
$totalFailed = 0
$results     = @()

Write-Host ""
Write-Host "================================================" -ForegroundColor Cyan
Write-Host "  Invoice Processing Agent — Endpoint Tests"     -ForegroundColor Cyan
Write-Host "================================================" -ForegroundColor Cyan

foreach ($test in $tests) {
    $scriptPath = Join-Path $ScriptDir $test

    # Run each test in a child process so their counters are isolated
    $proc = Start-Process -FilePath "powershell.exe" `
        -ArgumentList "-NoProfile", "-ExecutionPolicy", "Bypass", "-File", $scriptPath `
        -PassThru -Wait -NoNewWindow

    $exitCode = $proc.ExitCode

    if ($exitCode -eq 0) {
        $results += [PSCustomObject]@{ Test = $test; Result = "PASS"; Failures = 0 }
        $totalPassed++
    } else {
        $results += [PSCustomObject]@{ Test = $test; Result = "FAIL"; Failures = $exitCode }
        $totalFailed++
    }
}

# Final summary table
Write-Host ""
Write-Host "================================================" -ForegroundColor Cyan
Write-Host "  Summary" -ForegroundColor Cyan
Write-Host "================================================" -ForegroundColor Cyan

foreach ($r in $results) {
    if ($r.Result -eq "PASS") {
        Write-Host ("  [PASS]  " + $r.Test) -ForegroundColor Green
    } else {
        Write-Host ("  [FAIL]  " + $r.Test + "  ($($r.Failures) assertion(s) failed)") -ForegroundColor Red
    }
}

Write-Host ""
$total = $totalPassed + $totalFailed
if ($totalFailed -eq 0) {
    Write-Host "  ALL $total TESTS PASSED" -ForegroundColor Green
} else {
    Write-Host "  $totalPassed/$total tests passed  ($totalFailed failed)" -ForegroundColor Red
}
Write-Host ""

exit $totalFailed

