# Shared helpers for all test scripts

$BaseUrl = "http://localhost:8000"

$PassCount = 0
$FailCount = 0

function Assert-Equal {
    param($Label, $Expected, $Actual)
    if ($Actual -eq $Expected) {
        Write-Host "  [PASS] $Label" -ForegroundColor Green
        $script:PassCount++
    } else {
        Write-Host "  [FAIL] $Label" -ForegroundColor Red
        Write-Host "         Expected : $Expected" -ForegroundColor DarkRed
        Write-Host "         Got      : $Actual"   -ForegroundColor DarkRed
        $script:FailCount++
    }
}

function Assert-Contains {
    param($Label, $Substring, $Text)
    if ($Text -match [regex]::Escape($Substring)) {
        Write-Host "  [PASS] $Label" -ForegroundColor Green
        $script:PassCount++
    } else {
        Write-Host "  [FAIL] $Label" -ForegroundColor Red
        Write-Host "         Expected to contain: $Substring" -ForegroundColor DarkRed
        $script:FailCount++
    }
}

function Assert-NotContains {
    param($Label, $Substring, $Text)
    if (-not ($Text -match [regex]::Escape($Substring))) {
        Write-Host "  [PASS] $Label" -ForegroundColor Green
        $script:PassCount++
    } else {
        Write-Host "  [FAIL] $Label" -ForegroundColor Red
        Write-Host "         Expected NOT to contain: $Substring" -ForegroundColor DarkRed
        $script:FailCount++
    }
}

function Assert-StatusCode {
    param($Label, $Expected, $Actual)
    Assert-Equal $Label $Expected $Actual
}

function Write-TestHeader {
    param($Title)
    Write-Host ""
    Write-Host "=== $Title ===" -ForegroundColor Cyan
}

function Write-Summary {
    param($TestFile)
    $total = $script:PassCount + $script:FailCount
    Write-Host ""
    if ($script:FailCount -eq 0) {
        Write-Host "  $TestFile : $($script:PassCount)/$total passed" -ForegroundColor Green
    } else {
        Write-Host "  $TestFile : $($script:PassCount)/$total passed ($($script:FailCount) failed)" -ForegroundColor Red
    }
    return $script:FailCount
}

function Test-ServerRunning {
    try {
        $null = Invoke-WebRequest -Uri "$BaseUrl/health" -Method GET -TimeoutSec 3 -ErrorAction Stop
        return $true
    } catch {
        Write-Host "  ERROR: Server not reachable at $BaseUrl" -ForegroundColor Red
        Write-Host "         Start it with: uvicorn src.main:app --reload --port 8000" -ForegroundColor Yellow
        return $false
    }
}

function Invoke-SSERequest {
    param(
        [string]$Uri,
        [string]$Method = "POST",
        [hashtable]$Headers = @{},
        [string]$Body = $null,
        [string]$ContentType = "application/json"
    )
    try {
        $params = @{
            Uri         = $Uri
            Method      = $Method
            TimeoutSec  = 60
            ErrorAction = "Stop"
        }
        if ($Body) {
            $params.Body        = $Body
            $params.ContentType = $ContentType
        }
        foreach ($key in $Headers.Keys) {
            $params.Headers[$key] = $Headers[$key]
        }
        $response = Invoke-WebRequest @params
        return @{ StatusCode = $response.StatusCode; Content = $response.Content }
    } catch [System.Net.WebException] {
        $resp = $_.Exception.Response
        if ($resp) {
            $reader  = [System.IO.StreamReader]::new($resp.GetResponseStream())
            $content = $reader.ReadToEnd()
            return @{ StatusCode = [int]$resp.StatusCode; Content = $content }
        }
        return @{ StatusCode = 0; Content = $_.Exception.Message }
    } catch {
        return @{ StatusCode = 0; Content = $_.Exception.Message }
    }
}
